public int maxMinProduct(int[] nums) {
    long res = 0, mod = 1_000_000_007;
    int n = nums.length;
    int[] prefix = new int[n + 1];
    Stack<Integer> s = new Stack<>();

    for (int i = 0; i < n; ++i) {
        prefix[i + 1] = (int)((prefix[i] + nums[i]) % mod);
    }

    for (int i = 0; i <= n; ++i) {
        while (!s.isEmpty() && (i == n || nums[s.peek()] > nums[i])) {
            int j = s.pop();
            res = Math.max(res, nums[j] * (long)(prefix[i] - prefix[s.isEmpty() ? 0 : s.peek() + 1]) % mod);
        }
        s.push(i);
    }

    return (int)res;
}
```

